    related_articles: ["čl. 160. ZPP","čl. 161. ZPP","čl. 54. ZPP","čl. 8. ZPP","čl. 182. ZPP","čl. 156. ZPP","čl. 338. ZPP","čl. 339. ZPP","čl. 350. ZPP","čl. 42. ZPP"],
